import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import { isReadServerTextData } from '@common/constants/env'
import {
  IconDelete,
  IconEdit,
  IconPlus,
  IconInfoCircle,
} from '@arco-design/web-react/icon'
import { renderEllipsisText } from '@common/components/EllipsisText'
import { MaxLengthEnum } from '@common/constants/maxLength'

import { useEffect, useState } from 'react'
import { v4 as uuidv4 } from 'uuid'
import {
  converTimeFormat,
  generateUniqueId,
  getHitHalfMonths,
  getInitPercentBySelectWeeks,
  handelActivitiesData,
  handlePlanedStartDateLogic,
  milestonePercent,
  milestoneW2W4Percent,
  truncateString,
  weightOfEachWeekArr,
} from '@/utils/processActivitiesTime'
import _ from 'lodash'
import './index.less'
import useProjectInfo from '../../../../../../hooks/useProjectInfo'
import dayjs from 'dayjs'
import { LanguageEnum } from '@common/constants/language'
import { getLanguage } from '@common/utils/localStorage'
import {
  getActivityPersonByProjectId,
  getActivityPersonCopyByProjectId,
  projectMilestoneImportExcel,
} from '@/service/index'
import { ProjectPublishedEnum, InvalidStatus } from '@/constants/project'
import { useRequest } from 'ahooks'
import { useParams } from 'react-router-dom'
import axios from 'axios'
import useDebouncedPromise from '@common/hooks/useDebouncedPromise.ts'
import ModifyActivityFields from '@common/components/ModifyActivityFields'
import { findIdsByUserIds, getMailString } from '@/utils/tools.ts'
import DiscardWaringIcon from '@/assets/images/icon/discardWaringIcon.svg?react'

const FormItem = Form.Item
const Row = Grid.Row
const Col = Grid.Col
const TabPane = Tabs.TabPane
const TextArea = Input.TextArea
const Option = Select.Option

/** 预算 Tab 各周字段初始值（与 handleAddRow 一致） */
const emptyBudgetRecord = () => ({
  janW2: 0,
  janW4: 0,
  febW2: 0,
  febW4: 0,
  marW2: 0,
  marW4: 0,
  aprW2: 0,
  aprW4: 0,
  mayW2: 0,
  mayW4: 0,
  junW2: 0,
  junW4: 0,
  julW2: 0,
  julW4: 0,
  augW2: 0,
  augW4: 0,
  sepW2: 0,
  sepW4: 0,
  octW2: 0,
  octW4: 0,
  novW2: 0,
  novW4: 0,
  decW2: 0,
  decW4: 0,
})

/**
 * 接口无里程碑数据时用于联调：2 条里程碑，各带 1 条活动（周、预算结构齐全）
 * 项目起止用 DD/MM/YYYY，缺省时用当年 1/1～12/31
 */
const buildMockMilestoneActivitiesTwo = (
  projectStartDDMMYYYY: string,
  projectEndDDMMYYYY: string,
) => {
  const ps = projectStartDDMMYYYY || '01/01/2025'
  const pe = projectEndDDMMYYYY || '31/12/2025'
  const selectWeeks = getHitHalfMonths(
    converTimeFormat(ps),
    converTimeFormat(pe),
  )
  const initWeightOfEachWeek = getInitPercentBySelectWeeks(selectWeeks)
  const mid1 = generateUniqueId()
  const mid2 = generateUniqueId()
  const aid1 = uuidv4()
  const aid2 = uuidv4()

  return [
    {
      id: 'mock-milestone-1',
      mid: mid1,
      name: 'Milestone A (Mock)',
      weight: 50,
      activityDetails: [
        {
          id: '',
          activityId: '',
          aid: aid1,
          name: 'Activity A1',
          output: 'Mock output for milestone A',
          responsiblePersonList: [],
          weight: 50,
          enableEditDate: true,
          planedStartDate: ps,
          planedEndDate: pe,
          weightOfEachWeek: { ...initWeightOfEachWeek },
          budget: emptyBudgetRecord(),
          selectWeeks,
          invalidStatus: InvalidStatus.normal,
          reason: '',
        },
      ],
    },
    {
      id: 'mock-milestone-2',
      mid: mid2,
      name: 'Milestone B (Mock)',
      weight: 50,
      activityDetails: [
        {
          id: '',
          activityId: '',
          aid: aid2,
          name: 'Activity B1',
          output: 'Mock output for milestone B',
          responsiblePersonList: [],
          weight: 50,
          enableEditDate: true,
          planedStartDate: ps,
          planedEndDate: pe,
          weightOfEachWeek: { ...initWeightOfEachWeek },
          budget: emptyBudgetRecord(),
          selectWeeks,
          invalidStatus: InvalidStatus.normal,
          reason: '',
        },
      ],
    },
  ]
}

/**
 * 项目活动设置：按里程碑维护活动列表（权重/周分布/预算 Tab）、发布态废弃活动、Excel 导入等
 */
/** 与 GeneralInfo / ActivitiesSettingTable 一致：活动计划日可选区间以「表单中的项目起止」优先，否则用详情中的起止 */
const formatDdMmYyyy = (v: any) => {
  if (v == null || v === '') return ''
  if (typeof v === 'object' && typeof v?.format === 'function') {
    return v.format('DD/MM/YYYY')
  }
  return typeof v === 'string' ? v : ''
}

const MilestoneTable = ({
  milestoneTableData,
  setMilestoneTableData,
  activityPersons,
  setActivityPersons,
  form,
}: {
  milestoneTableData: any
  setMilestoneTableData: any
  activityPersons: any
  setActivityPersons: any
  form?: any
}) => {
  const { id, pedit } = useParams()
  let cancelUpload
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const isProjectPublishedEdit =
    Number(pedit) === ProjectPublishedEnum.PublishedProjectEdit ? true : false
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['project', 'common'])
  const { milestoneActivities, projectDetailInfo, getProjectDetailInfo } =
    useProjectInfo()
  const { startDate, endDate, budget, projectId, status } = projectDetailInfo
  const startDateWatch = form ? Form.useWatch('startDate', form) : undefined
  const endDateWatch = form ? Form.useWatch('endDate', form) : undefined
  /** 里程碑活动 DatePicker 边界：与 ActivitiesSettingTable 使用同一套项目起止，但优先取 GeneralInfo 表单当前值 */
  const projectStartForActivities =
    formatDdMmYyyy(startDateWatch) || startDate || ''
  const projectEndForActivities = formatDdMmYyyy(endDateWatch) || endDate || ''
  const maxBudget = budget ?? 0
  /** InputNumber 清空时多为 undefined/null，参与 += 会得到 NaN，需统一成有限数字 */
  const toFiniteNumber = (v, fallback = 0) => {
    if (v === null || v === undefined || v === '') return fallback
    const n = Number(v)
    return Number.isFinite(n) ? n : fallback
  }
  /** 活动行主键：业务用 aid，勿用 id（常为空串，会导致每行 key 相同） */
  const getActivityRowKey = (milestoneItem) => (record) =>
    record.aid ||
    record.id ||
    record.activityId ||
    `${milestoneItem.mid}_${record.name}_${record.planedStartDate}_${record.planedEndDate}`
  // const [activityPersons, setActivityPersons] = useState([])
  // const [activityPersons1, setActivityPersons1] = useState({})

  /** 接口无数据时用两条模拟里程碑；有数据则走真实接口 */
  const milestoneActivitiesSource = milestoneActivities
  /** 汇总某里程碑下「有效」活动的 weight 之和（排除废弃），用于展示里程碑权重 */
  const handelActivityWeightSum = (data) => {
    const newData = data.filter((m) => m.invalidStatus === InvalidStatus.normal)
    const sum = newData.reduce((acc, cur) => {
      return acc + cur.weight
    }, 0)
    return Math.round(sum * 100) / 100
  }
  const milestoneActivitiesNew = milestoneActivitiesSource.map((item) => ({
    ...item,
    weight: handelActivityWeightSum(item?.activityDetails),
  }))
  const initMilestoneTableData = _.isEmpty(milestoneActivitiesNew)
    ? []
    : milestoneActivitiesNew

  // const [milestoneTableData, setMilestoneTableData] = useState([])
  const [discardTableData, setDiscardTableData] = useState([])
  const [discardTableActivityCount, setDiscardTableActivityCount] = useState(0)
  const [totalBudget, setTotalBudget] = useState([])
  const [addMilestoneVisible, setAddMilestoneVisible] = useState(false)
  const [uploadExcelVisible, setUploadExcelVisible] = useState(false)
  const [budgetLeftPercent, setBudgetLeftPercent] = useState('')
  const [changeBorderColor, setChangeBorderColor] = useState(false)
  const [fileList, setFileList] = useState([])
  const [uploadFileErrorData, setUploadFileErrorData] = useState([])
  const [isModifyActivityShow, setIsModifyActivityShow] = useState(false)
  const [modifyKey, setModifyKey] = useState('')
  const [modifyIndexM, setModifyIndexM] = useState(0)
  const [modifyIndexA, setModifyIndexA] = useState(0)
  const [modifyValue, setModifyValue] = useState('')
  const [modifyLimit, setModifyLimit] = useState(500)
  const [modifyLabelName, setModifyLabelName] = useState('')
  const [discardActivityVisible, setDiscardActivityVisible] = useState(false)
  const [switchLoading, setSwitchLoading] = useState(false)

  /**
   * 从里程碑数据中拆出「已废弃」活动到 discard 侧，主表只保留非废弃活动，并统计废弃条数
   */
  const getInitDiscardTableData = (data) => {
    let discardActivityTableCount = 0
    const mTableDate = data.map((item) => {
      const filteredActivities = item.activityDetails
      const discardActivityTable = item.activityDetails.filter(
        (activity) => activity.invalidStatus === InvalidStatus.discard,
      )
      discardActivityTableCount += discardActivityTable.length
      // Return a new object with the filtered activities
      return {
        ...item,
        activityDetails: filteredActivities,
      }
    })
    setDiscardTableActivityCount(discardActivityTableCount)
    return mTableDate
  }

  /**
   * 遍历所有里程碑活动预算，计算每个里程碑预算展示文案、剩余预算、并补全 mid/aid/weight 等派生字段
   */
  /** @param dataOverride 若传入（如 handleInputChange 内刚改完的表），必须用该快照计算；否则会用仍为旧值的 state，把新输入覆盖掉 */
  const getBudgetPercent = (dataOverride?) => {
    let totalBudgetArr = []
    const hasOverride =
      dataOverride !== undefined &&
      dataOverride !== null &&
      !_.isEmpty(dataOverride)
    // handleInputChange 传入的已是 cloneDeep 后的可写副本；来自 props 的 milestoneTableData 可能被 Immer 冻结，不可原地改 budget
    const milestoneTableDataNew = hasOverride
      ? dataOverride
      : !_.isEmpty(milestoneTableData)
        ? _.cloneDeep(milestoneTableData)
        : _.cloneDeep(milestoneActivities)
    let allTotalBudget = 0
    milestoneTableDataNew.forEach((item, index) => {
      let totalBudget = 0
      item.activityDetails.forEach((detail) => {
        for (let key in detail.budget) {
          if (detail.budget.hasOwnProperty(key)) {
            const cell = toFiniteNumber(detail.budget[key], 0)
            detail.budget[key] = cell
            totalBudget += cell
            allTotalBudget += cell
          }
        }
        detail['aid'] = detail?.aid ? detail?.aid : generateUniqueId()
      })
      const nowBudget = Number(toFiniteNumber(totalBudget, 0)).toFixed(2)
      const totalBudgetToNumber = Number(
        maxBudget > 0 ? (totalBudget / maxBudget) * 100 : 0,
      ).toFixed(2)
      totalBudgetArr[index] =
        `${nowBudget}/${maxBudget ?? '--'} AED (${totalBudgetToNumber}%)`
      item.totalBudget = `${nowBudget}/${maxBudget ?? '--'} AED (${totalBudgetToNumber}%)`
      item['mid'] = item?.mid ? item?.mid : generateUniqueId()
      item['weight'] = handelActivityWeightSum(item?.activityDetails)
    })
    const remainingBudget = Number(
      toFiniteNumber(maxBudget, 0) - toFiniteNumber(allTotalBudget, 0),
    ).toFixed(2)
    const totalLeftPercent = `${remainingBudget}`
    setBudgetLeftPercent(totalLeftPercent)
    setTotalBudget(totalBudgetArr)
    return milestoneTableDataNew
  }

  /**
   * 仅随接口里程碑数据初始化/变更：拉表 + 预算汇总。
   * 禁止 useEffect([milestoneTableData]) 内 getBudgetPercent+setState：每次 cloneDeep 新引用会死循环。
   */
  useEffect(() => {
    const mTableDate = getInitDiscardTableData(initMilestoneTableData)
    const raw = _.cloneDeep(mTableDate)
    if (!_.isEmpty(raw)) {
      setMilestoneTableData(getBudgetPercent(raw))
    } else {
      setMilestoneTableData(raw)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [milestoneActivities])

  /**
   * 父组件直接写入的里程碑（如 AI generate）不会经过 milestoneActivities，需补算 totalBudget；
   * 仅当仍缺汇总字段时才 setState，避免与 getBudgetPercent(clone) 形成死循环。
   */
  useEffect(() => {
    if (_.isEmpty(milestoneTableData)) return
    const needsEnrich = milestoneTableData.some(
      (item) =>
        item?.totalBudget == null ||
        item?.totalBudget === '' ||
        typeof item?.totalBudget === 'undefined',
    )
    if (!needsEnrich) return
    setMilestoneTableData(getBudgetPercent(_.cloneDeep(milestoneTableData)))
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [milestoneTableData])

  /**
   * 按项目 ID 拉取可选活动负责人（草稿/已发布编辑用不同接口），结果写入 activityPersons 下拉与映射表
   */
  const { loading, run: getAllActivityPersons } = useRequest(
    isProjectPublishedEdit
      ? getActivityPersonCopyByProjectId
      : getActivityPersonByProjectId,
    {
      manual: true,
      onSuccess(data: any, params) {
        let activityPersons = {}
        const activityPersonsOptions = data?.map((item) => {
          activityPersons[item.userId] = isLanguageAR ? item.nameAr : item.name
          return {
            label: isLanguageAR
              ? `${item.nameAr}(${getMailString(item.mail)})`
              : `${item.name}(${getMailString(item.mail)})`,
            value: item.userId,
          }
        })
        setActivityPersons(activityPersonsOptions || [])
        // setActivityPersons1(activityPersons || {})
      },
      onError(e, params) {
        console.log({ e, params })
      },
    },
  )
  /** 路由项目 id 就绪后拉取负责人列表 */
  useEffect(() => {
    if (!_.isEmpty(id)) {
      getAllActivityPersons(id)
    }
  }, [id])

  /**
   * 新建活动时默认计划起止：开始对齐项目开始；结束按年度/与项目结束关系推算（与业务卡点一致）
   */
  const getActivityStartAndEndDate = () => {
    const ps = projectStartForActivities
    const pe = projectEndForActivities
    if (!ps || !pe) {
      return { startDate: ps || '', activityEndDate: pe || '' }
    }
    const activityStartDate = converTimeFormat(ps)
    const Year = activityStartDate.split('-')[0] //获取当前年
    const activityEndDate = dayjs(activityStartDate).isSame(
      dayjs(dayjs(`${Year}-12-31`)),
    )
      ? dayjs(activityStartDate).format('DD/MM/YYYY')
      : dayjs(converTimeFormat(ps))
            .add(1, 'day')
            .isBefore(dayjs(converTimeFormat(pe)))
        ? dayjs(activityStartDate).add(1, 'day').format('DD/MM/YYYY')
        : dayjs(converTimeFormat(pe)).format('DD/MM/YYYY') //结束时间卡点判断，如果开始时间+1day 还是在project的结束时间之前，则Activity时间+1day 否则结束时间就是project的结束时间

    return { startDate: ps, activityEndDate }
  }

  /** 预算 Tab：单月金额占项目总预算的百分比展示（用于 InputNumber 旁辅助文案） */
  const getBudgetPercentMoney = (value) => {
    const newValue = toFiniteNumber(value, 0)
    const monthBudgetMoney =
      maxBudget > 0 ? Number((newValue / budget) * 100).toFixed(2) : 0
    return (
      <span className='show-month-budget' title={monthBudgetMoney + `%`}>
        {monthBudgetMoney + `%`}
      </span>
    )
  }
  /**
   * Q1 子列（Jan–Mar 双周）：milestoneTab 为周权重输入，budgetTab 为对应月预算输入
   * getChildQ2 / Q3 / Q4 结构相同，仅覆盖月份区间不同
   */
  const getChildQ1 = (tabType, index) => {
    const childQ1 = [
      {
        title: t('project:projectActivityTablecolumns.qChild1.janW2'),
        dataIndex:
          tabType === 'budgetTab' ? 'budget.janW2' : 'weightOfEachWeek.janW2',
        width: 150,
        render:
          tabType === 'budgetTab'
            ? (_, record, i) => (
                <>
                  <InputNumber
                    disabled={
                      !record.selectWeeks.includes('janW2') ||
                      maxBudget <= 0 ||
                      isDiscardData(record?.invalidStatus)
                    }
                    min={0}
                    max={maxBudget}
                    step={0.01}
                    precision={0.01}
                    value={
                      record.budget.janW2 === undefined
                        ? 0
                        : record.budget.janW2
                    }
                    defaultValue={
                      record.budget.janW2 === undefined
                        ? 0
                        : record.budget.janW2
                    }
                    maxLength={MaxLengthEnum.NameInput}
                    placeholder={t('common:pleaseEnter')}
                    suffix='AED'
                    onChange={(e) =>
                      handleInputChange('janW2', index, i, e, true)
                    }
                  />
                  {getBudgetPercentMoney(record.budget.janW2)}
                </>
              )
            : (_, record, i) => (
                <>
                  <InputNumber
                    disabled={
                      !record.selectWeeks.includes('janW2') ||
                      isDiscardData(record?.invalidStatus)
                    }
                    min={0}
                    max={100}
                    step={0.01}
                    precision={0.01}
                    value={record.weightOfEachWeek.janW2}
                    defaultValue={record.weightOfEachWeek.janW2}
                    maxLength={MaxLengthEnum.NameInput}
                    placeholder={t('common:pleaseEnter')}
                    suffix='%'
                    onChange={(e) =>
                      handleInputChange('janW2', index, i, e, false, true)
                    }
                  />
                </>
              ),
      },
      {
        title: t('project:projectActivityTablecolumns.qChild1.janW4'),
        dataIndex:
          tabType === 'budgetTab' ? 'budget.janW4' : 'weightOfEachWeek.janW4',
        width: 150,
        render:
          tabType === 'budgetTab'
            ? (_, record, i) => (
                <>
                  <InputNumber
                    disabled={
                      !record.selectWeeks.includes('janW4') ||
                      maxBudget <= 0 ||
                      isDiscardData(record?.invalidStatus)
                    }
                    min={0}
                    max={maxBudget}
                    step={0.01}
                    precision={0.01}
                    value={
                      record.budget.janW4 === undefined
                        ? 0
                        : record.budget.janW4
                    }
                    defaultValue={
                      record.budget.janW4 === undefined
                        ? 0
                        : record.budget.janW4
                    }
                    maxLength={MaxLengthEnum.NameInput}
                    placeholder={t('common:pleaseEnter')}
                    suffix='AED'
                    onChange={(e) =>
                      handleInputChange('janW4', index, i, e, true)
                    }
                  />
                  {getBudgetPercentMoney(record.budget.janW4)}
                </>
              )
            : (_, record, i) => (
                <>
                  <InputNumber
                    disabled={
                      !record.selectWeeks.includes('janW4') ||
                      isDiscardData(record?.invalidStatus)
                    }
                    min={0}
                    max={100}
                    step={0.01}
                    precision={0.01}
                    value={record.weightOfEachWeek.janW4}
                    defaultValue={record.weightOfEachWeek.janW4}
                    maxLength={MaxLengthEnum.NameInput}
                    placeholder={t('common:pleaseEnter')}
                    suffix='%'
                    onChange={(e) =>
                      handleInputChange('janW4', index, i, e, false, true)
                    }
                  />
                </>
              ),
      },
      {
        title: t('project:projectActivityTablecolumns.qChild1.febW2'),
        dataIndex:
          tabType === 'budgetTab' ? 'budget.febW2' : 'weightOfEachWeek.febW2',
        width: 150,
        render:
          tabType === 'budgetTab'
            ? (_, record, i) => (
                <>
                  <InputNumber
                    disabled={
                      !record.selectWeeks.includes('febW2') ||
                      maxBudget <= 0 ||
                      isDiscardData(record?.invalidStatus)
                    }
                    min={0}
                    max={maxBudget}
                    step={0.01}
                    precision={0.01}
                    value={
                      record.budget.febW2 === undefined
                        ? 0
                        : record.budget.febW2
                    }
                    defaultValue={
                      record.budget.febW2 === undefined
                        ? 0
                        : record.budget.febW2
                    }
                    maxLength={MaxLengthEnum.NameInput}
                    placeholder={t('common:pleaseEnter')}
                    suffix='AED'
                    onChange={(e) =>
                      handleInputChange('febW2', index, i, e, true)
                    }
                  />
                  {getBudgetPercentMoney(record.budget.febW2)}
                </>
              )
            : (_, record, i) => (
                <>
                  <InputNumber
                    disabled={
                      !record.selectWeeks.includes('febW2') ||
                      isDiscardData(record?.invalidStatus)
                    }
                    min={0}
                    max={100}
                    step={0.01}
                    precision={0.01}
                    value={record.weightOfEachWeek.febW2}
                    defaultValue={record.weightOfEachWeek.febW2}
                    maxLength={MaxLengthEnum.NameInput}
                    placeholder={t('common:pleaseEnter')}
                    suffix='%'
                    onChange={(e) =>
                      handleInputChange('febW2', index, i, e, false, true)
                    }
                  />
                </>
              ),
      },
      {
        title: t('project:projectActivityTablecolumns.qChild1.febW4'),
        dataIndex:
          tabType === 'budgetTab' ? 'budget.febW4' : 'weightOfEachWeek.febW4',
        width: 150,
        render:
          tabType === 'budgetTab'
            ? (_, record, i) => (
                <>
                  <InputNumber
                    disabled={
                      !record.selectWeeks.includes('febW4') ||
                      maxBudget <= 0 ||
                      isDiscardData(record?.invalidStatus)
                    }
                    min={0}
                    max={maxBudget}
                    step={0.01}
                    precision={0.01}
                    value={
                      record.budget.febW4 === undefined
                        ? 0
                        : record.budget.febW4
                    }
                    defaultValue={
                      record.budget.febW4 === undefined
                        ? 0
                        : record.budget.febW4
                    }
                    maxLength={MaxLengthEnum.NameInput}
                    placeholder={t('common:pleaseEnter')}
                    suffix='AED'
                    onChange={(e) =>
                      handleInputChange('febW4', index, i, e, true)
                    }
                  />
                  {getBudgetPercentMoney(record.budget.febW4)}
                </>
              )
            : (_, record, i) => (
                <>
                  <InputNumber
                    disabled={
                      !record.selectWeeks.includes('febW4') ||
                      isDiscardData(record?.invalidStatus)
                    }
                    min={0}
                    max={100}
                    step={0.01}
                    precision={0.01}
                    value={record.weightOfEachWeek.febW4}
                    defaultValue={record.weightOfEachWeek.febW4}
                    maxLength={MaxLengthEnum.NameInput}
                    placeholder={t('common:pleaseEnter')}
                    suffix='%'
                    onChange={(e) =>
                      handleInputChange('febW4', index, i, e, false, true)
                    }
                  />
                </>
              ),
      },
      {
        title: t('project:projectActivityTablecolumns.qChild1.marW2'),
        dataIndex:
          tabType === 'budgetTab' ? 'budget.marW2' : 'weightOfEachWeek.marW2',
        width: 150,
        render:
          tabType === 'budgetTab'
