/**
 * 删除里程碑或活动
 * @param type wrap 删除整段里程碑；inner 删除里程碑下一条活动
 * @param mid 里程碑 mid
 * @param aid 活动 aid（inner 时有效）
 */
const handleDeleteRow = (type, mid, aid) => {
  switch (type) {
    case 'wrap':
      {
        const list = milestoneTableData.filter((d) => d.mid !== mid)
        setMilestoneTableData(list)
      }
      break
    case 'inner':
      {
        const list = milestoneTableData.map((d) => {
          if (d.mid === mid) {
            d.activityDetails = d.activityDetails.filter((t) => t.aid !== aid)
          }
          return d
        })
        setMilestoneTableData(list)
      }
      break
  }
}

/** 汇总行：当前里程碑下有效活动 weight 合计（用于 Summary 第一块权重列） */
const handelOneMilestoneSummary = (currentData) => {
  const weightsSum = currentData
    .filter((m) => m.invalidStatus === InvalidStatus.normal)
    .reduce((prev, next) => prev + next.weight, 0)
  const weightsSumNew = Math.round(weightsSum * 100) / 100
  return weightsSumNew
}

/** 活动表底部汇总行：权重合计、周权重合计、添加活动按钮 */
const activityWeightSummary = (currentData, mid) => (
  <Table.Summary>
    <Table.Summary.Row style={{ background: '#fff' }}>
      <Table.Summary.Cell style={{ background: '#fff' }}></Table.Summary.Cell>
      <Table.Summary.Cell style={{ background: '#fff' }}></Table.Summary.Cell>
      <Table.Summary.Cell style={{ background: '#fff' }}></Table.Summary.Cell>
      <Table.Summary.Cell style={{ background: '#fff' }}></Table.Summary.Cell>
      <Table.Summary.Cell style={{ paddingLeft: '27px', background: '#fff' }}>
        {handelOneMilestoneSummary(currentData) + `%`}
      </Table.Summary.Cell>
      <Table.Summary.Cell style={{ background: '#fff' }}></Table.Summary.Cell>
      <Table.Summary.Cell style={{ background: '#fff' }}></Table.Summary.Cell>
      <Table.Summary.Cell
        colSpan={24}
        style={{ background: '#fff' }}
      ></Table.Summary.Cell>
      <Table.Summary.Cell style={{ background: '#fff' }}>
        {currentData
          .filter((m) => m.invalidStatus === InvalidStatus.normal)
          .reduce((prev, next) => {
            const weightOfEachWeekArr = Object.values(next.weightOfEachWeek)
            const weightOfEachWeekSum = weightOfEachWeekArr.reduce(
              (accumulator, currentValue) =>
                Number(accumulator) + Number(currentValue),
              0,
            )
            const weightOfEachWeekSumNew = Number(
              Number(weightOfEachWeekSum).toFixed(2),
            )
            return next.selectWeeks.length === 0
              ? prev + 0
              : prev + weightOfEachWeekSumNew
          }, 0) + `%`}
      </Table.Summary.Cell>
      <Table.Summary.Cell
        style={{ background: '#fff', cursor: 'pointer' }}
        onClick={() => handleAddRow('inner', currentData, mid)}
      >
        <IconPlus />
      </Table.Summary.Cell>
    </Table.Summary.Row>
  </Table.Summary>
)

/**
 * DatePicker 禁用日期：计划开始/结束需在项目周期内，结束还需不早于已选开始日
 */
const dataDisabled = (
  current,
  startDate,
  endDate,
  dateType,
  selectPlanedStartDate = '',
) => {
  if (!startDate || !endDate) return true
  const dayjsCurrent = dayjs(current)
  const startDateArr = converTimeFormat(startDate)
  const endDateArr = converTimeFormat(endDate)
  let selectPlanedStartDateNew = ''
  if (!_.isEmpty(selectPlanedStartDate)) {
    selectPlanedStartDateNew = converTimeFormat(selectPlanedStartDate)
  } else {
    selectPlanedStartDateNew = startDateArr
  }

  if (dateType === 'planedStartDate') {
    if (startDateArr === endDateArr) {
      return !dayjsCurrent.isSame(startDateArr, 'day')
    }
    return (
      dayjsCurrent.isBefore(dayjs(startDateArr)) ||
      dayjsCurrent.isAfter(dayjs(endDateArr))
    )
  } else {
    if (startDateArr === endDateArr) {
      return !dayjsCurrent.isSame(startDateArr, 'day')
    }
    const endataStart = dayjs(selectPlanedStartDateNew).isAfter(
      dayjs(startDateArr),
    )
      ? dayjs(selectPlanedStartDateNew)
      : dayjs(startDateArr)
    return (
      dayjsCurrent.isBefore(endataStart) || dayjsCurrent.isAfter(endDateArr)
    )
  }
}

