  mindex,
  aindex,
  value,
  isBudget = false,
  isActivity = false,
) => {
  // 须深拷贝：嵌套对象可能来自 Immer/Redux 等为只读，浅拷贝数组仍会共享 budget / weightOfEachWeek 引用
  const newMilestoneTableData = _.cloneDeep(milestoneTableData)
  isBudget
    ? (newMilestoneTableData[mindex]['activityDetails'][aindex]['budget'][
        key
      ] = toFiniteNumber(value, 0))
    : isActivity
      ? (newMilestoneTableData[mindex]['activityDetails'][aindex][
          'weightOfEachWeek'
        ][key] = toFiniteNumber(value, 0))
      : (newMilestoneTableData[mindex]['activityDetails'][aindex][key] =
          key === 'weight' ? toFiniteNumber(value, 0) : value)
  // 预算列：getBudgetPercent 必须基于 newMilestoneTableData；若读 milestoneTableData，此时仍是本次 render 的旧 state，会立刻把新输入覆盖回 0
  if (isBudget) {
    setMilestoneTableData(getBudgetPercent(newMilestoneTableData))
    return
  }
  // 周权重字段：同步突变后一次性提交，避免 setTimeout 二次渲染导致闪烁
  if (weightOfEachWeekArr.includes(key) && isActivity) {
    milestoneW2W4Percent(newMilestoneTableData, mindex, aindex)
    setMilestoneTableData(_.cloneDeep(newMilestoneTableData))
    return
  }
  // Activity Weight：先同步更新里程碑汇总权重和 selectWeeks，再重算周分布，最后一次提交
  if (key === 'weight') {
    handelActivitiesData(newMilestoneTableData, setMilestoneTableData)
    milestonePercent(newMilestoneTableData, mindex, aindex, key)
    setMilestoneTableData(_.cloneDeep(newMilestoneTableData))
    return
  }
  // 重新选择开始时间时，清空结束时间
  if (key === 'planedStartDate') {
    newMilestoneTableData[mindex]['activityDetails'][aindex]['planedEndDate'] =
      handlePlanedStartDateLogic(
        newMilestoneTableData[mindex]['activityDetails'][aindex][
          'planedStartDate'
        ],
        newMilestoneTableData[mindex]['activityDetails'][aindex][
          'planedEndDate'
        ],
      )
  }
  // 日期变更：同步更新 selectWeeks 和周分布后一次性提交
  if (key === 'planedStartDate' || key === 'planedEndDate') {
    handelActivitiesData(newMilestoneTableData, setMilestoneTableData)
    milestonePercent(newMilestoneTableData, mindex, aindex, key)
    setMilestoneTableData(_.cloneDeep(newMilestoneTableData))
    return
  }
  setMilestoneTableData(newMilestoneTableData)
}
